class User_Model_LoginLog extends User_Model_Base_LoginLog {

    /**
     * @param Doctrine_Connection|null $conn
     */
    public function save(Doctrine_Connection $conn = null) {
        if ( $this->ID == null ) {
            $this->Date = date('Y-m-d');
            $this->Time = date('H:i:s');
        }
        
        parent::save();
    }

    /**
     * @param string $type
     * @param int $userID
     */
    public static function createLoginLog(string $type, int $userID) {
        $loginLog = new User_Model_LoginLog();
        $loginLog->User_ID = $userID;
        $loginLog->Type = $type;
        $loginLog->save();
    }
}